import scala.annotation.tailrec

object Solution {

  /**
   * Checks if a number n is prime.
   */
  def isPrime(n: Long): Boolean = {
    if (n <= 1) return false
    if (n <= 3) return true
    if (n % 2 == 0 || n % 3 == 0) return false
    var i = 5L
    while (i * i <= n) {
      if (n % i == 0 || n % (i + 2) == 0) return false
      i += 6
    }
    true
  }

  /**
   * Finds the smallest number >= start that satisfies the condition.
   * 
   * @param start The starting number.
   * @param requiredPrime If true, finds the smallest prime >= start. If false, finds the smallest non-prime >= start.
   * @return The required target number.
   */
  def findTarget(start: Long, requiredPrime: Boolean): Long = {
    var current = start
    while (requiredPrime == isPrime(current)) {
      current += 1
    }
    current
  }

  /**
   * Solves the alternating prime array transformation problem.
   * The signature must be: solve: def nums(Array[Long]): Long
   */
  def nums(nums: Array[Long]): Long = {
    var totalCost: Long = 0

    for (i <- nums.indices) {
      val originalValue = nums(i)
      var cost: Long = 0

      if (i % 2 == 0) {
        // Even index: Must be Prime
        val target = findTarget(originalValue, requiredPrime = true)
        cost = target - originalValue
      } else {
        // Odd index: Must be Non-Prime
        val target = findTarget(originalValue, requiredPrime = false)
        cost = target - originalValue
      }

      totalCost += cost
    }

    totalCost
  }
}
```

